var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"그러니까 내가 이렇게 증언하고 있지 않느냐!! 헤비암즈 대표가 범인이라고!","JPN":"だからここで私が証言してるじゃない！！　ヘビーアームズ代表が犯人だって！","ENG":"That’s why I’m here testifying, is it not?! It was all the CEO of Heavyarms’ doing!","TWN":"我剛不就一直在作證嗎？犯人是重武裝！！"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"그 녀석이 실행범에게 밸런스 브레이커를 줘서 지아에게 누명을 씌우려 했단 말이다!","JPN":"あいつが実行犯にバランスブレイカーを渡して、\\nユイちゃんに濡れ衣を着せようとしたのよ！","ENG":"He gave the killer the Balance Breaker and tried to frame it on Jia!","TWN":"那傢伙將平衡破壞者交給行兇的人，再把罪名誣賴給小佳！"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"봐라! 여기 사건 현장에서 발견된 탄두와 공장에 남아 있던 생산 이력이 그 증거지!","JPN":"ほら、見なさい！　事件現場で見つかった弾頭と工場に残っていた生産履歴がその証拠よ！","ENG":"Here! This is the bullet found at the crime scene, and here’s the log from the factory!","TWN":"你們看！這是在案發現場發現的彈頭，和在工廠找到的生產履歷，這就是證據！"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"조용! 다들 조용히!","JPN":"静かに！　全員、静かに！","ENG":"Everyone! Silence!","TWN":"安靜！都給我安靜！"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DIRECTORB_NPC_ALPHA_NULL","text":{"KOREA":"이사님, 어떻게 생각하십니까?","JPN":"理事、どう思いますか？","ENG":"What do you think of this, sir?","TWN":"理事，您怎麼看？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"크흠, 증거를 분석한 수사기관 말로는 조작한 흔적이 없답니다.","JPN":"コホン、証拠を分析した捜査機関の話では、ねつ造した形跡はないようです。","ENG":"Ahem, according to the investigation unit, they found no traces of tampering with the evidence.","TWN":"咳咳，根據搜查機關分析後的結果，並沒有偽造的痕跡。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DIRECTORB_NPC_ALPHA_NULL","text":{"KOREA":"하지만 그게 사실이라면 저희는 지금까지…….","JPN":"しかしそれが事実なら、私たちはこれまで……","ENG":"But if this is true, then...","TWN":"如果她說的是真的，就表示我們一直都誤……"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"이, 이 사람아. 목소리 좀 낮추지 않고.","JPN":"お、おい！　それを言ったら……","ENG":"L-lower your voice!","TWN":"喂，你小聲點！"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ELECTRONICSCEO_NPC_ALPHA_NULL","text":{"KOREA":"이사님들, 제가 잠시 발언해도 괜찮겠습니까?","JPN":"理事会の皆様、私から発言してもよろしいでしょうか？","ENG":"Directors, if I may.","TWN":"理事，我可以說幾句話嗎？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ELECTRONICSCEO_NPC_ALPHA_NULL","text":{"KOREA":"신지아 CEO에 대해 증언할 것이 있습니다.","JPN":"ヒメノ・ユイCEOについて証言したいことがあります。","ENG":"I have something to say with regards to Miss Shin Jia.","TWN":"我可以替沈佳CEO作證。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"그러니까…… 신지아 대표가 귀하의 목숨을 구하고 범인을 뒤쫓았단 말씀이오?","JPN":"つまり……ヒメノ・ユイ代表があなたの命を救い、犯人を追いかけたということでしょうか？","ENG":"So... She saved your life and went after the killer?","TWN":"就是……沈佳代表救了你後，去追犯人是嗎？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ELECTRONICSCEO_NPC_ALPHA_NULL","text":{"KOREA":"제 보디가드들도 목격한 사실입니다.","JPN":"私のボディーガードたちも目撃した事実です。","ENG":"My bodyguards can verify this fact.","TWN":"我的保鑣也有目擊到當時的情況。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ELECTRONICSCEO_NPC_ALPHA_NULL","text":{"KOREA":"게다가 신지아 CEO는 자기 능력을 제대로 활용할 수 없는 상태였어요. 자작극일 가능성은 낮습니다.","JPN":"それにヒメノ・ユイCEOは自身の能力をまともに使えない状態でした。\\n自作自演の可能性は極めて低いでしょう。","ENG":"Miss Shin Jia was also unable to use her powers. As a result, the possibility of this being a self-fabricated scenario is extremely unlikely.","TWN":"更何況，以當時的環境，沈佳CEO並無法使用自己的能力，所以不太可能是自編自導自演。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DIRECTORB_NPC_ALPHA_NULL","text":{"KOREA":"으음, 두 건의 사건에 대해서는 어느 정도 결론이 내려진 것 같습니다.","JPN":"ふむ、２つの事件について、ある程度結論が出たようですね。","ENG":"Mm... I see that we’ve come to a conclusion on the two cases then.","TWN":"嗯嗯，針對這兩件事似乎已經有釐出一些脈絡。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DIRECTORB_NPC_ALPHA_NULL","text":{"KOREA":"하지만 아직 헤비암즈 대표의 죽음에 대해서는 충분히 논의되지 않은 것 같군요.","JPN":"しかし、ヘビーアームズ代表の死についてはまだ十分に議論されていないと\\n思いますが。","ENG":"But regarding the death of Mr. Shin Jaehyuk, I believe there is more to discuss.","TWN":"不過關於重武裝代表的死，似乎還有討論的空間。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DIRECTORB_NPC_ALPHA_NULL","text":{"KOREA":"하실 말씀 있으십니까, 신지아 대표?","JPN":"何か言いたいことはありますか、ヒメノ・ユイ代表？","ENG":"Is there anything else you would like to say, Miss Shin Jia?","TWN":"你有話要說嗎，沈佳代表？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"범인은…….","JPN":"犯人は……","ENG":"But the killer was...","TWN":"犯人……"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};